/**
 * Element-attached host wrapper reader for web components mounted as
 * `kind: 'component'` panels in the gen-2-chat managed-layout shell.
 *
 * The host stamps a panel-scoped wrapper as `__wippyHost` on each
 * element BEFORE it is appended to the DOM (see the host's
 * `panel-context-wires.ts` and `host-scope.ts`). Consumer web
 * components read it back via `getWippyHost(this)` in
 * `connectedCallback` and onwards.
 *
 * The wrapper is **constructed by the host** — this package only
 * exposes the reader. Outside a managed-layout host (raw mounts,
 * compat shells, tests without the connector) the property is absent
 * and `getWippyHost` returns `null`.
 */

/**
 * Read the panel-scoped host wrapper attached to an element by the
 * managed-layout shell's content resolvers. Returns `null` outside a
 * managed-layout host (or before the element is connected).
 *
 * Subclass authors of `WippyElement` / `WippyVueElement` access this
 * via `this.host` / `useHost()` and rarely need to call this directly.
 * The helper is exposed for raw `HTMLElement` consumers.
 */
export function getWippyHost<H = unknown>(el: HTMLElement): H | null {
  return ((el as unknown) as { __wippyHost?: H }).__wippyHost ?? null
}
