/**
 * Layout bus types shared between `@wippy-fe/webcomponent-core` and
 * `@wippy-fe/webcomponent-vue`. Mirror of the host-side
 * `LayoutBusBound` / `BroadcastEnvelope` shapes; structurally
 * compatible so a host-mounted web component can read its
 * `__wippyHostBus` property without importing host-private types.
 *
 * The host (gen-2-chat managed-layout shell) sets:
 *   - `el.dataset.wippyPanelId` (string)
 *   - `(el as { __wippyHostBus?: LayoutBusBound }).__wippyHostBus`
 * BEFORE the element is appended to the DOM. Web components see them
 * on first `connectedCallback` tick.
 *
 * Outside a managed-layout host, both are absent — read code MUST
 * tolerate `undefined`.
 *
 * The interface bodies live in `@wippy-fe/shared` so the host can
 * import them without dragging in this package's `@wippy-fe/proxy`
 * runtime dependency. Consumers continue to import from
 * `@wippy-fe/webcomponent-core` (this re-export) for backward compat.
 */

import type { LayoutBusBound } from '@wippy-fe/shared'

export type { BroadcastEnvelope, LayoutBusBound } from '@wippy-fe/shared'

/**
 * Read the host bus attached to an element by `ComponentResolver` in
 * the managed-layout host. Returns `null` outside a managed-layout
 * host (or before the element is connected). Stable across element
 * remounts of the same panel — the resolver re-attaches a fresh bus
 * each time.
 */
export function getWippyHostBus(el: HTMLElement): LayoutBusBound | null {
  return (el as { __wippyHostBus?: LayoutBusBound }).__wippyHostBus ?? null
}

/**
 * Read the panelId attribute set by `ComponentResolver`. `null`
 * outside a managed-layout host.
 */
export function getWippyPanelId(el: HTMLElement): string | null {
  return el.dataset.wippyPanelId ?? null
}
